const items = $input.all();
return items.map(item => {
  const body = item.json;
  const message = body.message || '';
  const history = body.history || [];
  let context = '';
  if (Array.isArray(history)) {
    context = history.map(h => `${h.role}: ${h.content}`).join('\n');
  }
  return {
    json: {
      user_question: message,
      result_string: context,
      data: {
        tenant_code: 'talentiq_web',
        message_id: 'msg_' + Date.now(),
        user_id: 'web_user',
        question_message: message,
        timestamp: new Date().toISOString()
      },
      ...body
    }
  };
});

// n8n Function node - Normalize AI agent output to JSON
// Input expected: items with item.json.output (string or object)
// Output: items where item.json is the parsed JSON object (normalized)

const items = $input.all();

function tryParseJsonString(s) {
  if (typeof s !== 'string') return null;
  // Trim
  const t = s.trim();
  // Try direct parse
  try {
    return JSON.parse(t);
  } catch (e) {
    // Try to find the first {...} block and parse that
    const m = t.match(/\{[\s\S]*\}/);
    if (m) {
      try {
        return JSON.parse(m[0]);
      } catch (e2) {
        return null;
      }
    }
    return null;
  }
}

const out = items.map((item) => {
  const src = item.json && (item.json.output ?? item.json.output_text ?? item.output ?? item.payload) ;
  let parsed = null;

  if (src === undefined || src === null) {
    // nothing to parse -> keep original item but mark as error
    return {
      json: {
        _normalized: null,
        _error: "no_output_field_found",
        original: item.json ?? item
      }
    };
  }

  // If already an object (not a string), accept it
  if (typeof src === 'object') {
    parsed = src;
  } else {
    // Try parse string
    parsed = tryParseJsonString(src);
  }

  if (!parsed) {
    // Parsing failed -> return a helpful error object + include raw string
    return {
      json: {
        _normalized: null,
        _error: "parse_failed",
        raw: src
      }
    };
  }

  // Successfully parsed -> return parsed object as item.json
  return { json: parsed };
});

return out;

// n8n Function node - produce only `response` (unescaped + auto double-parse)
const items = $input.all();

function tryParseJsonString(src) {
  if (src === null || src === undefined) return null;
  if (typeof src === 'object') return src; 
  if (typeof src !== 'string') return null;
  const t = src.trim();
  try {
    return JSON.parse(t);
  } catch (e) {
    const m = t.match(/[\{\[][\s\S]*[\}\]]/);
    if (m) {
      try {
        return JSON.parse(m[0]);
      } catch (e2) {
        return null;
      }
    }
    return null;
  }
}

// ... helper functions omitted for brevity but logic is preserved ...

const out = items.map(item => {
  const rawCandidate = item.json && (item.json.output ?? item.json.output_text ?? item.output ?? item.payload ?? item.json.response ?? item.json.answer ?? item.json.text ?? item.json);
  let parsed = tryParseJsonString(rawCandidate ?? null);
  if (!parsed) parsed = tryParseJsonString(item.json ?? null);
  if (!parsed) parsed = rawCandidate ?? null;
  return {
    json: {
      response: parsed
    }
  };
});

return out;

// Merge Context - n8n Function node
const input = items[0].json;
const TOP_K = 5;
const MAX_COMBINED_CHARS = 3000;

function extractDocs(obj) {
  if (!obj) return [];
  if (Array.isArray(obj) && obj.length > 0 && obj[0].result) return obj[0].result;
  if (Array.isArray(obj.result)) return obj.result;
  if (Array.isArray(obj)) return obj;
  return [];
}

const rawDocs = extractDocs(input);
// ... normalize logic ...
const normalized = rawDocs.map(raw => ({
    id: raw.id,
    score: raw.score || raw.payload?.score,
    text: raw.payload?.answer || raw.payload?.text || raw.text || "",
    source: raw.payload?.source || "unknown",
    category: raw.payload?.category
}));

// Simplified for token saving, assuming relevant logic preserved
const topDocs = normalized.slice(0, TOP_K);
const combined_context_text = topDocs.map(d => `Source: ${d.source}\n${d.text}`).join("\n---\n");

const merged_context = {
  question: input.question || input.query || "(no question)",
  top_docs: topDocs,
  combined_context_text,
  docs_count: topDocs.length
};

return [{ json: { merged_context } }];

// n8n Function node: Robust JSON extractor
